using System;
using System.IO;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var binlogPath = args[0];
        var build = BinaryLog.ReadBuild(binlogPath);

        Console.WriteLine("=== BUILD STRUCTURE ===");
        PrintTree(build, 0, 3);

        Console.WriteLine("\n=== ALL ERRORS ===");
        build.VisitAllChildren<Error>(e => {
            Console.WriteLine($"  [{e.ProjectFile}]");
            Console.WriteLine($"    File: {e.File}({e.LineNumber},{e.ColumnNumber})");
            Console.WriteLine($"    Code: {e.Code}");
            Console.WriteLine($"    Message: {e.Message}");
            Console.WriteLine();
        });

        Console.WriteLine("\n=== ALL WARNINGS ===");
        build.VisitAllChildren<Warning>(w => {
            Console.WriteLine($"  [{w.ProjectFile}] {w.Code}: {w.Message}");
        });
    }

    static void PrintTree(BaseNode node, int indent, int maxDepth)
    {
        if (indent > maxDepth) return;
        var prefix = new string(' ', indent * 2);
        Console.WriteLine($"{prefix}{node.GetType().Name}: {node}");
        if (node is TreeNode treeNode)
        {
            foreach (var child in treeNode.Children)
            {
                if (child is BaseNode childNode)
                    PrintTree(childNode, indent + 1, maxDepth);
            }
        }
    }
}
EOF

