            foreach(var c in tn.Children) {
                if (c is Item item)
                    Console.WriteLine($"    {item.Text}");
                else
                    Console.WriteLine($"    [{c.GetType().Name}] {c}");
            }
        }
    }
});

// Check the Api project for errors
