using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Let's examine Item properties
Console.WriteLine("=== ITEM PROPERTIES (from Services) ===");
int count = 0;
build.VisitAllChildren<AddItem>(ai => {
    var proj = ai.GetNearestParent<Project>();
    if (proj != null && proj.SourceFilePath != null && proj.SourceFilePath.Contains("Services") && 
        ai.Name == "PackageReference" && count < 5) {
        count++;
        Console.WriteLine($"  AddItem: {ai.Name}");
        Console.WriteLine($"    ToString: {ai}");
        if (ai.Children != null) {
            foreach(var c in ai.Children) {
                Console.WriteLine($"    Child [{c.GetType().Name}]: {c}");
                // Get all properties via reflection
                foreach(var p in c.GetType().GetProperties(BindingFlags.Public | BindingFlags.Instance)) {
                    try {
                        var val = p.GetValue(c);
                        if (val != null && val.ToString() != "" && val.ToString() != "0" && p.Name != "Parent")
                            Console.WriteLine($"      {p.Name} = {val}");
                    } catch {}
                }
            }
        }
    }
});

// Check using the old replay method - look for Csc command line
Console.WriteLine("\n=== CSC COMMAND LINE FOR Services ===");
build.VisitAllChildren<Task>(t => {
    if (t.Name == "Csc") {
        var proj = t.GetNearestParent<Project>();
        if (proj != null && proj.SourceFilePath != null && proj.SourceFilePath.Contains("Services")) {
            Console.WriteLine("  Found Csc task in Services");
            foreach(var c in t.Children) {
                if (c.ToString() != null && c.ToString().Contains("/reference")) {
                    var text = c.ToString();
                    // Print just a portion
                    Console.WriteLine($"    {text.Substring(0, Math.Min(500, text.Length))}...");
                }
            }
        }
    }
});

// Alternate: use Parameter to find package references 
Console.WriteLine("\n=== TASK PARAMETERS ===");
build.VisitAllChildren<Parameter>(p => {
    var proj = p.GetNearestParent<Project>();
    if (proj != null && proj.SourceFilePath != null && proj.SourceFilePath.Contains("Services")) {
        if (p.Name == "PackageReferences" || p.Name == "RestoreGraphItems") {
            Console.WriteLine($"  Parameter: {p.Name}");
            foreach(var c in p.Children)
                Console.WriteLine($"    {c}");
        }
    }
});
EOF

